:root {
  --bg: #0a0512;
  --bg-elev: #15102a;
  --bg-card: rgba(28, 22, 50, 0.78);
  --border: rgba(236, 72, 153, 0.18);
  --border-strong: rgba(236, 72, 153, 0.45);
  --text: #f3e8ff;
  --muted: #a89cc4;
  --hot: #ec4899;
  --warm: #f97316;
  --cool: #06b6d4;
  --accent: #a78bfa;
  --success: #4ade80;
  --code-bg: rgba(8, 4, 18, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.6);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

body {
  overflow-x: hidden;
  background:
    radial-gradient(900px 500px at 100% 0%, rgba(236, 72, 153, 0.22), transparent 60%),
    radial-gradient(800px 500px at 0% 100%, rgba(167, 139, 250, 0.22), transparent 60%),
    var(--bg);
}

.bg-aurora {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
}

.bg-aurora span {
  position: absolute;
  width: 600px;
  height: 600px;
  border-radius: 50%;
  filter: blur(120px);
  opacity: 0.35;
  animation: drift 22s ease-in-out infinite;
}

.bg-aurora span:nth-child(1) {
  background: var(--hot);
  top: -160px;
  left: -160px;
}
.bg-aurora span:nth-child(2) {
  background: var(--warm);
  top: 30%;
  right: -200px;
  animation-delay: -8s;
}
.bg-aurora span:nth-child(3) {
  background: var(--accent);
  bottom: -200px;
  left: 30%;
  animation-delay: -14s;
}

@keyframes drift {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33%      { transform: translate(40px, -40px) scale(1.08); }
  66%      { transform: translate(-30px, 30px) scale(0.95); }
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1080px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

.hero {
  text-align: center;
  margin-bottom: 48px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(28, 22, 50, 0.7);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

.badge .pulse {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--hot);
  box-shadow: 0 0 12px var(--hot);
  animation: pulse 1.4s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 0.6; transform: scale(0.9); }
  50%      { opacity: 1;   transform: scale(1.2); }
}

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
}

.gradient-text {
  background: linear-gradient(120deg, var(--hot) 0%, var(--warm) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.lede {
  max-width: 640px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--hot);
  font-size: 14px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 18px;
  border-radius: 10px;
  border: 1px solid transparent;
  font: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  color: var(--text);
  background: rgba(255, 255, 255, 0.06);
  white-space: nowrap;
  text-decoration: none;
}
.btn:hover { transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary {
  background: linear-gradient(120deg, var(--hot), var(--warm));
  color: #0a0512;
  box-shadow: 0 12px 30px -10px rgba(236, 72, 153, 0.6);
}

.btn-ghost { background: transparent; border-color: var(--border-strong); }
.btn-small { padding: 8px 14px; font-size: 13px; }

/* Tutorial steps */
.steps {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px 26px;
  margin-bottom: 32px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(12px);
}

.steps h2 {
  margin: 0 0 14px;
  font-size: 16px;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 8px;
}

.steps h2 .glow {
  color: var(--hot);
  font-size: 20px;
}

.steps ol {
  margin: 0;
  padding-left: 22px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
}

.steps ol code {
  background: var(--code-bg);
  padding: 1px 6px;
  border-radius: 4px;
  color: var(--hot);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
}

/* Cards */
.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 20px;
  margin-bottom: 32px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: transform 0.2s ease, border-color 0.2s ease;
}

.card:hover {
  transform: translateY(-2px);
  border-color: var(--border-strong);
}

.card header { display: flex; flex-direction: column; gap: 8px; }

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(236, 72, 153, 0.15);
  color: var(--hot);
}

.card h2 { font-size: 17px; margin: 0; font-weight: 700; }
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
}
.card p code {
  background: var(--code-bg);
  padding: 1px 5px;
  border-radius: 3px;
  color: var(--hot);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
}

/* State preservation widget */
.preserve {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.preserve-value {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 44px;
  font-weight: 800;
  color: var(--hot);
  text-align: center;
  font-variant-numeric: tabular-nums;
  letter-spacing: -0.02em;
}

.preserve-meta {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12px;
  color: var(--muted);
  text-align: center;
}

.preserve-controls {
  display: flex;
  gap: 6px;
  justify-content: center;
}

/* Tweak panel */
.tweak {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.tweak-label {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 28px;
  font-weight: 700;
  color: var(--text);
  text-align: center;
  padding: 14px;
  border-radius: 10px;
  border: 1px dashed var(--border-strong);
}

.tweak-hint {
  font-size: 12px;
  color: var(--muted);
  text-align: center;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.foot {
  text-align: center;
  margin-top: 36px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 640px) {
  #app { padding: 32px 16px 56px; }
  .card { padding: 18px; }
}

import React from 'react';
import ReactDOM from 'react-dom';
import App from './App';

ReactDOM.render(<App />, document.getElementById('app'));

const webpack = require('webpack');
const path = require('path');

const config = {
  mode: 'development',
  entry: [
    'react-hot-loader/patch',
    './src/index.js'
  ],
  output: {
    path: path.resolve(__dirname, 'dist'),
    filename: 'bundle.js'
  },
  module: {
    rules: [
      {
        test: /\.(js|jsx)$/,
        use: 'babel-loader',
        exclude: /node_modules|cdn_modules/
      }
    ]
  },
  resolveLoader: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  resolve: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ],
    extensions: [
      '.js',
      '.jsx'
    ],
    alias: {
      'react-dom': '@hot-loader/react-dom'
    }
  },
  devServer: {
    port: 9950,
    static: {
      directory: './dist'
    }
  }
};

module.exports = config;
